SQLLite.SQL:
UPDATE PAYMENTS PAY
SET    PAY.PAYABLE_ORDER_NUMBER_1 = DECODE(${param.print},'N',NULL, ${param.poNumber})
,      PAY.PO_TOTAL               = DECODE(${param.print},'N',NULL, ${param.poTotal})
,      PAY.PAYOUT_DATE            = TO_DATE(${param.itemDate}, 'YYYY-MM-DD')
,      PAY.PAYOUT_REPORT_ID       = ${param.reportId}
,      PAY.NOTES                  = PAY.NOTES||DECODE(${param.print},'N','Address Unknown'||' '||${param.caduReportId},NULL) 
WHERE  PAY.ADMIN_COURT_CODE       = ${param.adminCourtCode}
AND    PAY.TRANSACTION_NUMBER     = ${param.transactionNumber}
